import{c as e}from"./createSolutionPack-C_Q4-4X6.js";import"./index-CMPoedmy.js";const s=[[{steps:["A polynomial is an algebraic expression in which the powers of the variable are whole numbers.","Its general form is a0 + a1x + a2x^2 + ... + anx^n, where n is a whole number."],finalAnswer:"Answer: A polynomial is an algebraic expression with non-negative integer powers of the variable."},{steps:["The highest power of x in 5x^2 + 3x + 1 is 2.","The degree of a polynomial is the highest power with non-zero coefficient."],finalAnswer:"Answer: Degree = 2."},{steps:["7 has no variable term.","A non-zero constant is also a polynomial of degree 0."],finalAnswer:"Answer: Yes, 7 is a polynomial."},{steps:["The constant term is the term without x.","In x^2 + 4x + 9, the constant term is 9."],finalAnswer:"Answer: Constant term = 9."},{steps:["x + 5 has highest power 1.","A degree 1 polynomial is called a linear polynomial."],finalAnswer:"Answer: x + 5 is a linear polynomial."},{steps:["p(x) = x^2 + 2x + 3.","p(1) = 1^2 + 2(1) + 3 = 1 + 2 + 3 = 6."],finalAnswer:"Answer: p(1) = 6."},{steps:["A monomial has exactly one term.","An example is 5x^2."],finalAnswer:"Answer: One monomial example is 5x^2."},{steps:["A binomial has exactly two terms.","An example is x + 3."],finalAnswer:"Answer: One binomial example is x + 3."},{steps:["A zero of x - 8 is the value of x that makes it equal to 0.","Set x - 8 = 0, so x = 8."],finalAnswer:"Answer: The zero is 8."},{steps:["A linear polynomial has degree 1.","Its graph is a straight line, which cuts the x-axis at one point."],finalAnswer:"Answer: A linear polynomial has one zero."}],[{steps:["p(x) = x^2 - 3x + 4.","p(-2) = (-2)^2 - 3(-2) + 4 = 4 + 6 + 4 = 14."],finalAnswer:"Answer: p(-2) = 14."},{steps:["Substitute x = 2 in x^2 - 5x + 6.","2^2 - 5(2) + 6 = 4 - 10 + 6 = 0."],finalAnswer:"Answer: Yes, 2 is a zero of x^2 - 5x + 6."},{steps:["The highest power of x in 4x^3 - x + 7 is 3.","A degree 3 polynomial is called a cubic polynomial."],finalAnswer:"Answer: Degree = 3, so it is a cubic polynomial."},{steps:["Compare x^2 - 7x + 10 with ax^2 + bx + c.","Here a = 1, b = -7, and c = 10."],finalAnswer:"Answer: The coefficients are 1, -7, and 10."},{steps:["x^2 - 9 = x^2 - 3^2.","Using difference of squares, x^2 - 9 = (x - 3)(x + 3).","Set each factor equal to 0."],finalAnswer:"Answer: The zeroes are 3 and -3."},{steps:["The zeroes of a polynomial are the x-coordinates of the points where its graph meets the x-axis.","If the graph does not meet the x-axis, then the polynomial has no real zero at that point."],finalAnswer:"Answer: Geometrically, zeroes are the points where the graph cuts or touches the x-axis."},{steps:["For x^2 - 4x + 3, a = 1, b = -4, c = 3.","Sum of zeroes = -b/a = -(-4)/1 = 4.","Product of zeroes = c/a = 3/1 = 3."],finalAnswer:"Answer: Sum = 4 and product = 3."},{steps:["If the zeroes are 1 and 4, then sum = 5 and product = 4.","Required polynomial = x^2 - (sum)x + product."],finalAnswer:"Answer: The quadratic polynomial is x^2 - 5x + 4."},{steps:["1/x can be written as x^-1.","A polynomial cannot have negative powers of the variable."],finalAnswer:"Answer: No, 1/x + 2 is not a polynomial."},{steps:["p(x) = 2x^2 - x - 6.","p(3) = 2(3^2) - 3 - 6 = 18 - 3 - 6 = 9."],finalAnswer:"Answer: p(3) = 9."}],[{steps:["Factor 2x^2 - 7x + 3.","2x^2 - 7x + 3 = 2x^2 - 6x - x + 3 = 2x(x - 3) - 1(x - 3).","So 2x^2 - 7x + 3 = (2x - 1)(x - 3)."],finalAnswer:"Answer: The zeroes are 1/2 and 3."},{steps:["For x^2 - 6x + 8, factorize: (x - 2)(x - 4).","So the zeroes are 2 and 4.","alpha + beta = 2 + 4 = 6 = -(-6)/1.","alpha beta = 2 x 4 = 8 = 8/1."],finalAnswer:"Answer: The relation between zeroes and coefficients is verified."},{steps:["If sum of zeroes = 7 and product = 12, use x^2 - (sum)x + product."],finalAnswer:"Answer: The required polynomial is x^2 - 7x + 12."},{steps:["If 2 is a zero of x^2 + kx + 2, then substituting x = 2 gives 0.","2^2 + 2k + 2 = 0","4 + 2k + 2 = 0 => 2k + 6 = 0 => k = -3."],finalAnswer:"Answer: k = -3."},{steps:["Substitute x = -1 into 2x^3 + x^2 - x - 2.","2(-1)^3 + (-1)^2 - (-1) - 2 = -2 + 1 + 1 - 2 = -2.","Since the value is not 0, x = -1 is not a zero."],finalAnswer:"Answer: No, x = -1 is not a zero."},{steps:["For zeroes -2 and 5, sum = 3 and product = -10.","Required polynomial = x^2 - 3x - 10."],finalAnswer:"Answer: A polynomial with zeroes -2 and 5 is x^2 - 3x - 10."},{steps:["x^2 + x - 12 = x^2 + 4x - 3x - 12.","Factor by grouping: x(x + 4) - 3(x + 4) = (x + 4)(x - 3)."],finalAnswer:"Answer: The zeroes are -4 and 3."},{steps:["Given alpha + beta = 3 and alpha beta = -10.","Required polynomial = x^2 - (alpha + beta)x + alpha beta."],finalAnswer:"Answer: The polynomial is x^2 - 3x - 10."},{steps:["p(x) = x^3 - 4x + 1.","p(-1) = (-1)^3 - 4(-1) + 1 = -1 + 4 + 1 = 4."],finalAnswer:"Answer: p(-1) = 4."},{steps:["In x^(1/2) + 3, the exponent of x is 1/2.","A polynomial allows only whole number exponents."],finalAnswer:"Answer: x^(1/2) + 3 is not a polynomial."}],[{steps:["Use the quadratic formula for 3x^2 - 11x - 4 = 0.","Discriminant = (-11)^2 - 4(3)(-4) = 121 + 48 = 169.","sqrt(169) = 13.","x = (11 +- 13)/6 gives x = 4 and x = -1/3."],finalAnswer:"Answer: The zeroes are 4 and -1/3."},{steps:["Since 2 is a zero of 2x^2 - 5x + k, substitute x = 2.","2(2^2) - 5(2) + k = 0 => 8 - 10 + k = 0 => k = 2.","The polynomial becomes 2x^2 - 5x + 2 = (2x - 1)(x - 2)."],finalAnswer:"Answer: k = 2 and the other zero is 1/2."},{steps:["Zeroes are 3/2 and -4.","Sum = 3/2 - 4 = -5/2 and product = (3/2)(-4) = -6.","Polynomial = x^2 - (sum)x + product = x^2 + 5x/2 - 6.","Multiply by 2 to avoid fractions."],finalAnswer:"Answer: A suitable polynomial is 2x^2 + 5x - 12."},{steps:["For sum = -1 and product = -6, use x^2 - (sum)x + product.","So the polynomial is x^2 + x - 6."],finalAnswer:"Answer: The required polynomial is x^2 + x - 6."},{steps:["For x^2 - px + 12, the sum of zeroes is -(-p)/1 = p.","Given alpha + beta = 7, so p = 7."],finalAnswer:"Answer: p = 7."},{steps:["x^4 + 2x^2 + 1 = (x^2 + 1)^2.","For any real x, x^2 >= 0, so x^2 + 1 > 0.","Therefore, (x^2 + 1)^2 is always positive and never 0."],finalAnswer:"Answer: It has no real zeroes."},{steps:["x^2 - 2x - 15 = x^2 - 5x + 3x - 15.","Factorize: x(x - 5) + 3(x - 5) = (x - 5)(x + 3).","Zeroes are 5 and -3.","Their sum = 5 + (-3) = 2 and product = 5(-3) = -15."],finalAnswer:"Answer: The zeroes are 5 and -3, with sum 2 and product -15."},{steps:["If 1 and -1 are the zeroes, then sum = 0 and product = -1.","Required polynomial = x^2 - 0x - 1."],finalAnswer:"Answer: The polynomial is x^2 - 1."},{steps:["If x + 2 is a factor, then x = -2 is a zero.","Substitute in x^2 + mx + 8: (-2)^2 + m(-2) + 8 = 0.","4 - 2m + 8 = 0 => 12 - 2m = 0 => m = 6."],finalAnswer:"Answer: m = 6."},{steps:["For p(x) = x^2 - 5x + 6, check the zeroes first.","p(2) = 4 - 10 + 6 = 0 and p(3) = 9 - 15 + 6 = 0.","So 2 and 3 are zeroes, and p(x) factorizes as (x - 2)(x - 3)."],finalAnswer:"Answer: If k is a zero, then x - k is a factor. Here the factors are x - 2 and x - 3."},{steps:["4x^2 - 4x - 3 = 4x^2 - 6x + 2x - 3.","Factor by grouping: 2x(2x - 3) + 1(2x - 3).","So 4x^2 - 4x - 3 = (2x - 3)(2x + 1)."],finalAnswer:"Answer: The zeroes are 3/2 and -1/2."},{steps:["Equal zeroes mean the graph intersects the x-axis at the same point twice.","So the parabola just touches the x-axis and turns back."],finalAnswer:"Answer: Its graph is a parabola touching the x-axis at exactly one point."},{steps:["Zeroes 5 and -3 give sum = 2 and product = -15.","Polynomial = x^2 - 2x - 15.","Coefficient relation check: -(-2)/1 = 2 and -15/1 = -15."],finalAnswer:"Answer: The polynomial is x^2 - 2x - 15, and the coefficient relation is verified."},{steps:["For p(x) = x^2 - 6x + 8:","p(1) = 1 - 6 + 8 = 3","p(2) = 4 - 12 + 8 = 0","p(3) = 9 - 18 + 8 = -1","Factorizing gives p(x) = (x - 2)(x - 4), so the zeroes are 2 and 4."],finalAnswer:"Answer: p(1) = 3, p(2) = 0, p(3) = -1, and the zeroes are 2 and 4."},{steps:["A polynomial has only non-negative integer powers of the variable and no variable in the denominator.","A rational expression is generally a ratio of two polynomials and may contain a variable in the denominator."],finalAnswer:"Answer: A polynomial is a special algebraic expression, while a rational expression can include a polynomial in the denominator."},{steps:["Original zeroes are 2 and -5.","Twice these zeroes are 4 and -10.","Sum = 4 + (-10) = -6 and product = 4(-10) = -40.","Required polynomial = x^2 - (sum)x + product = x^2 + 6x - 40."],finalAnswer:"Answer: The required polynomial is x^2 + 6x - 40."},{steps:["For x^2 + 6x + 8, alpha + beta = -6 and alpha beta = 8.","alpha^2 + beta^2 = (alpha + beta)^2 - 2 alpha beta.","= (-6)^2 - 2(8) = 36 - 16 = 20."],finalAnswer:"Answer: alpha^2 + beta^2 = 20."},{steps:["Reciprocal zeroes of 2 and 3 are 1/2 and 1/3.","Sum = 1/2 + 1/3 = 5/6 and product = 1/6.","Polynomial = x^2 - 5x/6 + 1/6.","Multiply by 6 for integer coefficients."],finalAnswer:"Answer: A suitable polynomial is 6x^2 - 5x + 1."},{steps:["p(1) = 1 - 6 + 11 - 6 = 0","p(2) = 8 - 24 + 22 - 6 = 0","p(3) = 27 - 54 + 33 - 6 = 0","Hence 1, 2, and 3 are all zeroes of the polynomial."],finalAnswer:"Answer: Yes, 1, 2, and 3 are zeroes of p(x) = x^3 - 6x^2 + 11x - 6."},{steps:["For any real number x, x^2 >= 0.","So x^2 + 1 is always at least 1, and never 0.","Therefore, although the polynomial is quadratic, it has no real zeroes."],finalAnswer:"Answer: x^2 + 1 has no real zeroes."}]],r=e("mathematics","polynomials","Detailed worked answers for every Polynomials practice question, written in the same order as the chapter practice set.",s);export{r as chapterSolutions};
